import { test, expect } from "@playwright/test";

// F018: Brian declares the Run Club
// Source: planning/scenarios-backlog/F018-brian-declares-run-club.md
//
// One test per Given/When/Then beat. The eval writer never reads code
// under web/src/ — this spec is written from the scenario alone.
//
// NOTE: this is a worked example for the pipeline walk-through. It will
// be regenerated by pipeline-eval (write mode) from the approved scenario
// once F018 promotes from scenarios-backlog/ to scenarios/.

test.describe("F018 — Brian declares the Run Club", () => {
  test.beforeEach(async ({ page }) => {
    // Seed: an authenticated Member "brian"; Drake's location exists at
    // /l/drakes-the-barn with kind=permanent.
    await page.goto("/test/reset?seed=f018"); // project's eval reset endpoint
  });

  test.describe("Brian discovers the entry point on the venue page", () => {
    test('Given Brian is on Drakes venue page | When the page loads | Then a "Host something here" CTA is visible below the header', async ({ page }) => {
      await page.goto("/l/drakes-the-barn");
      await expect(page.getByRole("button", { name: /Host something here/i })).toBeVisible();
    });
  });

  test.describe("The composer is location-aware and verb-shaped", () => {
    test("Given Brian taps the CTA | When the composer loads | Then Drake's is pre-attached and the kind question uses user language", async ({ page }) => {
      await page.goto("/l/drakes-the-barn");
      await page.getByRole("button", { name: /Host something here/i }).click();
      // Composer drawer opens
      await expect(page.getByRole("dialog", { name: /host something/i })).toBeVisible();
      // Location pre-attached
      await expect(page.getByLabel(/where/i)).toHaveValue(/drake/i);
      // Kind question in user language — NOT "Product/Service/Gathering/Wonder"
      const composer = page.getByRole("dialog");
      await expect(composer.getByText(/what kind of thing/i)).toBeVisible();
      await expect(composer.getByLabel(/one-time event/i)).toBeVisible();
      await expect(composer.getByLabel(/recurring gathering/i)).toBeVisible();
      await expect(composer.getByLabel(/open meetup/i)).toBeVisible();
      await expect(composer.getByText(/^Product$/)).toHaveCount(0);
      await expect(composer.getByText(/^Gathering$/)).toHaveCount(0);
    });
  });

  test.describe("Recurring gathering creates a published Item with an RRULE", () => {
    test("Given Brian fills required fields | When he submits | Then the Item is created and published", async ({ page }) => {
      await page.goto("/l/drakes-the-barn");
      await page.getByRole("button", { name: /Host something here/i }).click();
      const composer = page.getByRole("dialog");
      await composer.getByLabel(/recurring gathering/i).check();
      await composer.getByLabel(/title/i).fill("Unofficial Run Club");
      await composer.getByLabel(/description/i).fill("5K easy pace, all welcome, beer after");
      await composer.getByLabel(/day/i).selectOption("Thursday");
      await composer.getByLabel(/time/i).fill("18:00");
      await composer.getByRole("button", { name: /publish/i }).click();
      // Redirect to /i/[slug]
      await expect(page).toHaveURL(/\/i\/unofficial-run-club/);
    });
  });

  test.describe("The Item page shows next occurrence and supports a QR", () => {
    test("Given the Run Club is published | When anyone opens the Item page | Then next occurrence + QR action are present", async ({ page }) => {
      // Pre-seed the Item via the test reset endpoint
      await page.goto("/test/reset?seed=f018-published");
      await page.goto("/i/unofficial-run-club");
      await expect(page.getByRole("heading", { name: /Unofficial Run Club/i })).toBeVisible();
      // Next occurrence rendered as human-readable date
      await expect(page.getByText(/Thursday/i)).toBeVisible();
      await expect(page.getByText(/6:00 PM/i)).toBeVisible();
      // QR action
      const downloadPromise = page.waitForEvent("download");
      await page.getByRole("button", { name: /Print QR card/i }).click();
      const download = await downloadPromise;
      expect(download.suggestedFilename()).toBe("unofficial-run-club-qr.pdf");
    });
  });

  test.describe("The Item appears on the venue page and locality index", () => {
    test("Given the Run Club is published | When another user opens Drakes venue page | Then it appears under What's happening here", async ({ page }) => {
      await page.goto("/test/reset?seed=f018-published");
      await page.goto("/l/drakes-the-barn");
      const section = page.getByRole("region", { name: /What's happening here/i });
      await expect(section.getByText(/Unofficial Run Club/i)).toBeVisible();
      await expect(section.getByText(/Thursday/i)).toBeVisible();
    });

    test("Given the Run Club is published | When a user within 10mi browses 'this week' | Then the Run Club is in the list", async ({ page }) => {
      await page.goto("/test/reset?seed=f018-published");
      // Set locality to Drake's zip via the cookie/localStorage path the home uses
      await page.goto("/?zip=95605&filter=this-week");
      await expect(page.getByText(/Unofficial Run Club/i)).toBeVisible();
    });
  });
});
